const body = $input.first().json.body ?? $input.first().json;
const { job_id, file_url, ocr, ai } = body;
if (!job_id || !file_url || !ocr || !ai) throw new Error('Missing required fields');
const validOcr = ['tesseract','paddle'];
const validAi = ['ollama','openai','claude'];
if (!validOcr.includes(ocr)) throw new Error('Invalid OCR engine');
if (!validAi.includes(ai)) throw new Error('Invalid AI model');
return [{ json: { job_id, file_url, ocr, ai } }];

const item = $input.first();
let rawText = '';
if (item.json.text) rawText = item.json.text;
else if (item.json.result) rawText = item.json.result.flat().map(l => Array.isArray(l) ? l[1]?.[0] ?? '' : l).join(' ');
else if (typeof item.json === 'string') rawText = item.json;
const cleaned = rawText.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,'').replace(/[ \t]+/g,' ').replace(/\n{3,}/g,'\n\n').trim();
if (!cleaned || cleaned.length < 10) throw new Error('OCR produced no usable text');
return [{ json: { job_id: item.json.job_id, ocr: item.json.ocr, ai: item.json.ai, ocr_text: cleaned } }];

const item = $input.first();
let raw = '';
if (item.json.response !== undefined) raw = item.json.response;
else if (item.json.choices) raw = item.json.choices[0]?.message?.content ?? '';
else if (item.json.content) raw = item.json.content.find(b => b.type==='text')?.text ?? '';
raw = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
let sla;
try { sla = JSON.parse(raw); } catch { sla = { apr:null,monthly_payment:null,term:null,residual_value:null,mileage_limit:null,penalties:null }; }
const toNum = v => { const n = parseFloat(v); return isNaN(n) ? null : n; };
return [{ json: { job_id: item.json.job_id ?? $('Normalize OCR Text').first().json.job_id, ai: item.json.ai ?? $('Normalize OCR Text').first().json.ai, ocr_text: $('Normalize OCR Text').first().json.ocr_text, sla: { apr: toNum(sla.apr), monthly_payment: toNum(sla.monthly_payment), term: toNum(sla.term), residual_value: toNum(sla.residual_value), mileage_limit: toNum(sla.mileage_limit), penalties: typeof sla.penalties==='string' ? sla.penalties : null } } }];

const item = $input.first();
const text = item.json.ocr_text ?? '';
const vinRegex = /\b([A-HJ-NPR-Z0-9]{17})\b/g;
const matches = [...text.matchAll(vinRegex)];
const vin = matches.length > 0 ? matches[0][1] : null;
return [{ json: { ...item.json, detected_vin: vin } }];

const item = $input.first();
const results = item.json.Results ?? [];
const get = v => results.find(r => r.Variable===v)?.Value ?? null;
const make = get('Make'), model = get('Model'), year = parseInt(get('Model Year')??'0',10)||null;
const vin_data = (make&&model&&year) ? { vin: item.json.detected_vin??'', make, model, year } : null;
return [{ json: { ...item.json, vin: vin_data } }];

const item = $input.first();
const sla = item.json.sla ?? {};
const vin = item.json.vin ?? {};
const residual = sla.residual_value ?? 0;
const monthly = sla.monthly_payment ?? 0;
const term = sla.term ?? 36;
let market_value = residual + (monthly * term * 0.6);
if (vin?.year) { const age = new Date().getFullYear() - vin.year; market_value = market_value * Math.max(0.4, 1 - age * 0.12); }
let dp = 0;
if (sla.apr!==null) dp++; if (sla.monthly_payment!==null) dp++; if (sla.residual_value!==null) dp++; if (sla.term!==null) dp++; if (vin?.make) dp++;
return [{ json: { ...item.json, price_estimate: { market_value: Math.round(market_value), confidence: Math.round((dp/5)*100) } } }];

const item = $input.first();
const sla = item.json.sla ?? {};
const pe = item.json.price_estimate ?? {};
let aprScore=50, priceScore=50, mileageScore=50, penaltyScore=80;
if (sla.apr!==null) { if(sla.apr<=3)aprScore=100; else if(sla.apr<=5)aprScore=80; else if(sla.apr<=7)aprScore=60; else if(sla.apr<=10)aprScore=35; else aprScore=10; }
const total=(sla.monthly_payment??0)*(sla.term??36), market=pe.market_value??0;
if(market>0&&total>0){const r=total/market; if(r<=0.7)priceScore=100; else if(r<=0.85)priceScore=75; else if(r<=1)priceScore=50; else if(r<=1.2)priceScore=25; else priceScore=5;}
if(sla.mileage_limit!==null){if(sla.mileage_limit>=15000)mileageScore=100; else if(sla.mileage_limit>=12000)mileageScore=70; else if(sla.mileage_limit>=10000)mileageScore=40; else mileageScore=20;}
if(sla.penalties){const l=sla.penalties.toLowerCase(); if(l.includes('early termination'))penaltyScore=30; else if(l.includes('wear'))penaltyScore=50;}
const fairness_score=Math.round(aprScore*0.35+priceScore*0.30+mileageScore*0.20+penaltyScore*0.15);
return [{ json: { ...item.json, fairness_score } }];

const item = $input.first();
const sla = item.json.sla ?? {};
const score = item.json.fairness_score ?? 50;
const tips = [];
if (sla.apr!==null&&sla.apr>5) tips.push(`Your APR of ${sla.apr}% is above average. Negotiate for rates under 4%.`);
if (sla.apr!==null&&sla.apr>9) tips.push('Consider pre-approved financing from your bank.');
if (sla.monthly_payment!==null&&sla.monthly_payment>600) tips.push(`Monthly payment of $${sla.monthly_payment} is high. Ask for extended term or higher residual.`);
if (sla.mileage_limit!==null&&sla.mileage_limit<12000) tips.push(`${sla.mileage_limit.toLocaleString()} miles/year is restrictive. Negotiate for 15,000 miles.`);
if (sla.penalties&&sla.penalties.toLowerCase().includes('early termination')) tips.push('Ask dealer to cap early termination penalties.');
if (score<40) { tips.push('This contract scores poorly. Consider walking away or requesting full revision.'); tips.push('Get competing quotes from at least 2 other dealers.'); }
else if (score<70) tips.push('Focus negotiation on APR and monthly payment first.');
else tips.push('Contract appears competitive. Still review penalty clauses before signing.');
if (tips.length===0) tips.push('Compare total lease cost against buying the vehicle outright.');
return [{ json: { ...item.json, negotiation_tips: tips } }];
